import { config } from '@wagmi/test'
import { expect, test } from 'vitest'

import { getToken } from './getToken.js'

test('default', async () => {
  await expect(
    getToken(config, {
      address: '0x1f9840a85d5af5bf1d1762f925bdaddc4201f984',
    }),
  ).resolves.toMatchInlineSnapshot(`
    {
      "address": "0x1f9840a85d5af5bf1d1762f925bdaddc4201f984",
      "decimals": 18,
      "name": "Uniswap",
      "symbol": "UNI",
      "totalSupply": {
        "formatted": "1000000000",
        "value": 1000000000000000000000000000n,
      },
    }
  `)
})

test('parameters: formatUnits', async () => {
  await expect(
    getToken(config, {
      address: '0x1f9840a85d5af5bf1d1762f925bdaddc4201f984',
      formatUnits: 'gwei',
    }),
  ).resolves.toMatchInlineSnapshot(`
    {
      "address": "0x1f9840a85d5af5bf1d1762f925bdaddc4201f984",
      "decimals": 18,
      "name": "Uniswap",
      "symbol": "UNI",
      "totalSupply": {
        "formatted": "1000000000000000000",
        "value": 1000000000000000000000000000n,
      },
    }
  `)
})

test('behavior: bytes32 token', async () => {
  await expect(
    getToken(config, {
      address: '0x9f8f72aa9304c8b593d555f12ef6589cc3a579a2',
    }),
  ).resolves.toMatchInlineSnapshot(`
    {
      "address": "0x9f8f72aa9304c8b593d555f12ef6589cc3a579a2",
      "decimals": 18,
      "name": "Maker",
      "symbol": "MKR",
      "totalSupply": {
        "formatted": "977631.036950888222010062",
        "value": 977631036950888222010062n,
      },
    }
  `)
})

test('behavior: bogus token', async () => {
  await expect(
    getToken(config, {
      address: '0xa0cf798816d4b9b9866b5330eea46a18382f251e',
    }),
  ).rejects.toThrowErrorMatchingInlineSnapshot(`
    [ContractFunctionExecutionError: HTTP request failed.

    Status: 400
    URL: http://127.0.0.1:8545/9648
    Request body: {"method":"eth_call","params":[{"data":"","to":"0xca11bde05977b3631167028862be2a173976ca11"},"latest"]}
     
    Raw Call Arguments:
      to:    0xca11bde05977b3631167028862be2a173976ca11
      data:  
     
    Contract Call:
      address:   0xca11bde05977b3631167028862be2a173976ca11
      function:  aggregate3((address target, bool allowFailure, bytes callData)[])
      args:                ([{"allowFailure":true,"callData":"0x313ce567","target":"0xa0cf798816d4b9b9866b5330eea46a18382f251e"},{"allowFailure":true,"callData":"0x06fdde03","target":"0xa0cf798816d4b9b9866b5330eea46a18382f251e"},{"allowFailure":true,"callData":"0x95d89b41","target":"0xa0cf798816d4b9b9866b5330eea46a18382f251e"},{"allowFailure":true,"callData":"0x18160ddd","target":"0xa0cf798816d4b9b9866b5330eea46a18382f251e"}])

    Docs: https://viem.sh/docs/contract/readContract
    Details: Bad Request
    Version: viem@2.44.0]
  `)
})
